mapper.select:
SELECT e.* from fc_expense e left join
uc_supplier s on e.supplierId = s.id WHERE 1 = 1


    AND (
    e.`code` LIKE concat('%', #{query.name}, '%') OR
    s.`code` LIKE concat('%', #{query.name}, '%') OR
    s.`name` LIKE concat('%', #{query.name}, '%')
    )



    AND e.`issueDate`  >=  #{query.startDate}


    AND e.`issueDate`  <=  #{query.endDate}


ORDER BY e.createdTime DESC
